int f(int n) {
    if (n == 0) return 0;
    return 1 + f(n - 1);
}
System.out.println(f(4));

void count(int n) {
    if (n == 0) return;
    System.out.print(n + " ");
    count(n - 1);
}
count(3);

int sum(int n) {
    if (n <= 0) return 0;
    return n + sum(n - 2);
}
System.out.println(sum(5));

void dfs(int n) {
    if (n == 0) { System.out.print("done "); return; }
    dfs(n - 1);
    System.out.print(n + " ");
}
dfs(3);
